const requiredFields = ['fullName', 'email', 'message', 'source'];
return $input.all().map((item) => {
  const body = item.json.body ?? {};
  const missingFields = requiredFields.filter((field) => !body[field]);
  return {
    json: {
      body,
      validation: {
        isValid: missingFields.length === 0,
        requiredFields,
        missingFields,
        proofMode: 'placeholder_test_payload_only',
        realCustomerDataUsed: false
      }
    }
  };
});

return $input.all().map((item) => {
  const body = item.json.body;
  return {
    json: {
      ...item.json,
      draftLead: {
        fullName: body.fullName,
        email: body.email,
        phone: body.phone ?? null,
        serviceInterest: body.serviceInterest ?? null,
        message: body.message,
        source: body.source,
        submittedAt: body.submittedAt ?? null,
        status: 'draft_placeholder_only',
        productionWrite: false,
        externalSystemWrite: false
      }
    }
  };
});

return $input.all().map((item) => ({
  json: {
    ...item.json,
    followUpTask: {
      title: 'Review construction website lead placeholder',
      owner: 'internal_follow_up_owner_placeholder',
      dueWindow: 'next_business_day_placeholder',
      status: 'placeholder_task_only',
      externalTaskCreated: false,
      outboundMessageAllowed: false
    }
  }
}));

return $input.all().map((item) => ({
  json: {
    ...item.json,
    draftLog: {
      eventType: 'construction_lead_intake_placeholder_received',
      loggedInsideWorkflowOnly: true,
      persistedToExternalSystem: false,
      containsRealCustomerData: false
    }
  }
}));

return $input.all().map((item) => ({
  json: {
    ...item.json,
    proofResult: {
      stoppedBeforeOutboundMessages: true,
      emailSent: false,
      smsSent: false,
      whatsappSent: false,
      realExternalApiCalled: false,
      credentialsUsed: false,
      productionWorkflowTouched: false,
      leadGenWorkflowTouched: false,
      aiReceptionistWorkflowTouched: false
    }
  }
}));
